text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시각",
        "decision": "스모크 테스트가 통과하는 경우 금요일 15:00 KST를 공개 릴리스 목표 시각으로 둔다.",
        "certainty": "confirmed"
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토로 넘어간다.",
        "certainty": "confirmed"
      }
    ],
    "non_decisions": {
      "rejected_proposals": [
        {
          "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경하자",
          "result": "rejected",
          "note": "해당 제안은 채택되지 않았다."
        }
      ],
      "internal_stretch_goals": [
        {
          "goal": "수요일 릴리스",
          "status": "internal_stretch_goal_only",
          "note": "공식 공개 릴리스 확정안이 아니라 내부 목표로만 언급되었다."
        }
      ],
      "unassigned_or_tentative_items": [
        {
          "item": "README 설치 절차를 목요일까지 가능하면 검토",
          "note": "필요성은 언급되었지만 담당자가 지정되지 않았다."
        }
      ]
    },
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있다.",
        "certainty": "confirmed"
      },
      {
        "risk": "README 설치 절차가 오래된 상태라면 릴리스 노트가 사용자에게 오해를 줄 수 있다.",
        "certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "open"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?",
        "status": "open"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 failure triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 목요일까지 가능하면 검토한다.",
      "due": "목요일 가능 시",
      "status": "tentative_unassigned",
      "source_certainty": "explicit"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 스모크 테스트 재실행 결과가 금요일 10:00 KST까지 공유되었는지 확인한다.",
      "스모크 테스트 통과 여부를 기준으로 금요일 15:00 KST 공개 릴리스 목표가 유지되는지 확인한다.",
      "Doyun의 failure triage note가 금요일 12:00 KST까지 action_items.md에 반영되었는지 확인한다.",
      "Minjun의 결과 공유 이후 Hara의 tarball 경로 확인 결과를 점검한다.",
      "README 설치 절차 검토의 담당자 지정 여부와 실제 검토 진행 여부를 확인한다.",
      "최종 릴리스 승인 권한자와 릴리스 노트의 수요일 스트레치 목표 언급 여부를 후속 결정 사항으로 추적한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "지정되지 않은 담당자",
      "명시되지 않은 추가 마감일",
      "확정되지 않은 승인자"
    ]
  },
  "non_invention_rules": [
    "회의 메모에 없는 고객명, 외부 파트너명, 예산 수치, 보안 사고, 프로덕션 장애, 법무 승인 요구사항을 추가하지 않는다.",
    "담당자가 지정되지 않은 항목에 임의로 owner를 부여하지 않는다.",
    "명시되지 않은 마감일을 추정하여 확정 사실처럼 쓰지 않는다.",
    "수요일 릴리스를 확정 일정으로 쓰지 않고 내부 스트레치 목표로만 기록한다.",
    "거절된 제안을 확정 결정처럼 재서술하지 않는다.",
    "열린 질문에 대해 답이 정해진 것처럼 쓰지 않는다."
  ]
}
